public final class ModelImportsCheck {
  private final Project myProject;
  private final SModel myModel;
  private final List<SLanguage> myAdditionalLanguages;
  private final List<SModelReference> myAdditionalModels;


  public ModelImportsCheck(Project mpsProject, SModel model) {
    myProject = mpsProject;
    myModel = model;
    myAdditionalLanguages = new ArrayList<SLanguage>();
    myAdditionalModels = new ArrayList<SModelReference>();
  }

  /**
   * Tells if the model meets used languages and model imports. When not, a remedy with user interaction (#configuredDialog()) or
   * a headless (TODO) alternative is possible.
   * 
   * Expects model read
   * If either collection of necessary elements contains duplicated, they'd get manifested as duplicates in required for import
   * The method is additive if invoked multiple times
   * 
   * @return false when supplied languages/models are not visible/aavlable in the model
   */
  public boolean checkSatisfied(final Collection<SLanguage> necessaryLanguages, final Collection<SModelReference> necessaryImports) {

    final LanguageRegistry langReg = myProject.getComponent(LanguageRegistry.class);
    List<SModelReference> allImportedModels = new ArrayList<SModelReference>();
    ModelDependencyResolver mdr = new ModelDependencyResolver(langReg, myProject.getRepository());
    //  XXX in fact, neither old allImportedModels nor MDR give us implicit imports, while one in necessaryImports may actually be imported already as implicit
    // need better way to deal with implicit imports.
    for (SModel sm : mdr.directImports(myModel)) {
      // XXX could just add ModelImports.getImportedModels directly, no point in resolving them to SModel.
      //    however, this mimics what SModelOperations.allImportedModels used to do for years.
      allImportedModels.add(sm.getReference());
    }
    // these are not aforementioned  'implicit=true' imports, just accessory models coming from used languages
    for (SModel sm : mdr.implicitImports(myModel)) {
      allImportedModels.add(sm.getReference());
    }

    // MDR doesn't include target model as its own import; denote imports to self are not necessary
    allImportedModels.add(myModel.getReference());
    for (SModelReference modelReference : necessaryImports) {
      assert modelReference != null;
      if (!(allImportedModels.contains(modelReference))) {
        myAdditionalModels.add(modelReference);
      }
    }
    SLanguageHierarchy langHierarchy = new SLanguageHierarchy(langReg, mdr.usedLanguages(myModel));
    Set<SLanguage> allVisibleLanguages = langHierarchy.getExtended();
    allVisibleLanguages.addAll(langHierarchy.getAggregated());
    for (SLanguage lang : necessaryLanguages) {
      if (!(allVisibleLanguages.contains(lang))) {
        myAdditionalLanguages.add(lang);
      }
    }
    return isSatisfied();
  }

  public boolean isSatisfied() {
    return myAdditionalLanguages.isEmpty() && myAdditionalModels.isEmpty();
  }

  public AddRequiredImportsDialog configuredDialog() {
    return new AddRequiredImportsDialog(myProject, myAdditionalModels.toArray(new SModelReference[0]), myAdditionalLanguages.toArray(new SLanguage[0]));
  }
}
